// Basahin at i-extract ang bawat entry    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Gumawa ng buong landas        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
